"use client"

import * as React from "react"
import { useTranslations, useLocale } from "next-intl"
import { motion, AnimatePresence } from "framer-motion"
import { 
  CreditCard, 
  RotateCcw, 
  Plus, 
  Search,
  Filter,
  Download,
  Terminal,
  Info
} from "lucide-react"
import { Button } from "@/components/ui/Button"
import { Input } from "@/components/ui/Input"
import { useToast } from "@/hooks/use-toast"

// Internal Components
import { SubscriptionStats } from "@/components/admin/subscriptions/SubscriptionStats"
import { PendingPayments } from "@/components/admin/subscriptions/PendingPayments"
import { SubscriptionTable } from "@/components/admin/subscriptions/SubscriptionTable"
import { ManualActivationModal } from "@/components/admin/subscriptions/ManualActivationModal"
import { ArtisanHistoryDrawer } from "@/components/admin/subscriptions/ArtisanHistoryDrawer"

export default function SubscriptionsAdminPage() {
  const t = useTranslations("admin.subscription_management")
  const common = useTranslations("common")
  const { toast } = useToast()
  const locale = useLocale()

  // State
  const [data, setData] = React.useState({
    stats: {},
    pending_payments: [],
    subscriptions: [],
    all_artisans: []
  })
  const [loading, setLoading] = React.useState(true)
  const [activeTab, setActiveTab] = React.useState("all")
  const [search, setSearch] = React.useState("")

  // Modals/Drawers State
  const [isManualModalOpen, setIsManualModalOpen] = React.useState(false)
  const [historyArtisan, setHistoryArtisan] = React.useState(null)
  const [isHistoryOpen, setIsHistoryOpen] = React.useState(false)

  // Fetch Data
  const fetchData = async () => {
    setLoading(true)
    try {
      const res = await fetch(`/api/admin/subscriptions?tab=${activeTab}&search=${search}`)
      const result = await res.json()
      setData(result)
    } catch (error) {
      toast({
        title: "Erreur",
        description: "Impossible de charger les données.",
        variant: "destructive"
      })
    } finally {
      setLoading(false)
    }
  }

  React.useEffect(() => {
    fetchData()
  }, [activeTab, search])

  // Actions
  const handleConfirmPayment = async (payment) => {
    try {
      const res = await fetch(`/api/admin/subscriptions/confirm/${payment.id}`, { method: 'POST' })
      if (res.ok) {
        toast({ title: t("manual_activation.success") })
        fetchData()
      }
    } catch (err) {
      console.error(err)
    }
  }

  const handleRejectPayment = async (payment) => {
    const motif = window.prompt("Motif du rejet (transmis à l'artisan) :")
    if (!motif) return

    try {
      const res = await fetch(`/api/admin/subscriptions/reject/${payment.id}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ motif })
      })
      if (res.ok) {
        toast({ title: "Paiement rejeté." })
        fetchData()
      }
    } catch (err) {
      console.error(err)
    }
  }

  const handleManualActivate = async (formData) => {
    try {
      const res = await fetch('/api/admin/subscriptions/manual-activate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      })
      if (res.ok) {
        setIsManualModalOpen(false)
        toast({ title: t("manual_activation.success") })
        fetchData()
      }
    } catch (err) {
      console.error(err)
    }
  }

  return (
    <div className="p-4 md:p-8 max-w-7xl mx-auto space-y-8 pb-20">
      {/* Header section */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <motion.div 
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            className="flex items-center gap-2 mb-2"
          >
            <div className="w-8 h-1 bg-blue-600 rounded-full" />
            <span className="text-sm font-black text-blue-600 uppercase tracking-widest italic flex items-center gap-2">
               DzArtisan Admin <span className="opacity-30">/</span> Finance
            </span>
          </motion.div>
          <h1 className="text-4xl font-black dark:text-white tracking-tight">
             {t("title")}
          </h1>
          <p className="text-slate-500 dark:text-slate-400 mt-1 max-w-xl font-medium">
             {t("subtitle")}
          </p>
        </div>

        <div className="flex items-center gap-2">
           <Button variant="outline" className="rounded-2xl h-12" onClick={fetchData}>
              <RotateCcw className="w-4 h-4 mr-2" />
              {t("refresh")}
           </Button>
           <Button 
            className="rounded-2xl h-12 bg-blue-600 hover:bg-blue-700 shadow-xl shadow-blue-500/20"
            onClick={() => setIsManualModalOpen(true)}
           >
              <Plus className="w-4 h-4 mr-2" />
              {t("manual_activation.btn")}
           </Button>
        </div>
      </div>

      {/* Stats Cards */}
      <SubscriptionStats stats={data.stats} />

      {/* Core Layout: Pending on top (if any), then main table */}
      <div className="grid grid-cols-1 gap-8">

        {/* Pending Payments Section - Priority View */}
        <PendingPayments 
          payments={data.pending_payments} 
          onConfirm={handleConfirmPayment}
          onReject={handleRejectPayment}
        />

        {/* Main List Section */}
        <div className="space-y-6">
           <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
              <h2 className="text-xl font-bold dark:text-white flex items-center gap-2">
                 <Filter className="w-5 h-5 text-slate-400" />
                 {t("table.history")}
              </h2>
              <div className="flex items-center gap-3 w-full md:w-auto">
                 <div className="relative flex-1 md:w-64">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <Input 
                      placeholder={t("manual_activation.search_artisan")}
                      className="pl-10 rounded-xl"
                      value={search}
                      onChange={e => setSearch(e.target.value)}
                    />
                 </div>
                 <Button variant="secondary" className="rounded-xl h-10 px-4">
                    <Download className="w-4 h-4 mr-2" />
                    CSV
                 </Button>
              </div>
           </div>

           <SubscriptionTable 
             subscriptions={data.subscriptions}
             loading={loading}
             activeTab={activeTab}
             onTabChange={setActiveTab}
             onViewHistory={(artisan) => {
               setHistoryArtisan(artisan)
               setIsHistoryOpen(true)
             }}
           />
        </div>
      </div>

      {/* Manual Activation Modal */}
      <ManualActivationModal 
        isOpen={isManualModalOpen}
        onClose={() => setIsManualModalOpen(false)}
        onActivate={handleManualActivate}
        artisans={data.all_artisans || []}
      />

      {/* History Drawer */}
      <ArtisanHistoryDrawer 
        isOpen={isHistoryOpen}
        onClose={() => setIsHistoryOpen(false)}
        artisan={historyArtisan}
      />

      {/* Admin Quick Tip */}
      <div className="mt-12 p-4 rounded-2xl bg-slate-100/50 dark:bg-slate-800/30 border border-slate-200 dark:border-slate-800 flex items-start gap-4">
         <div className="p-2 bg-white dark:bg-slate-700 rounded-lg text-slate-400">
            <Info className="w-5 h-5" />
         </div>
         <div>
            <h4 className="text-sm font-bold text-slate-900 dark:text-white mb-1">Information sur la conformité</h4>
            <p className="text-xs text-slate-500 leading-relaxed">
               Conformément à la réglementation de la Banque d'Algérie sur les services numériques, assurez-vous de conserver une trace numérique pour chaque preuve de virement CCP validé manuellement. Les audits pourront nécessiter ces documents.
            </p>
         </div>
      </div>
    </div>
  )
}

"use client"

import * as React from "react"
import { useTranslations, useLocale } from "next-intl"
import { motion, AnimatePresence } from "framer-motion"
import { 
  LayoutGrid, 
  List, 
  Map as MapIcon, 
  Search, 
  X, 
  Filter as FilterIcon,
  ChevronLeft,
  ChevronRight,
  Zap,
  Clock,
  Briefcase,
  AlertCircle
} from "lucide-react"
import dynamic from 'next/dynamic'
import { Button } from "@/components/ui/Button"
import { Input } from "@/components/ui/Input"
import { Badge } from "@/components/ui/Badge"
import { ArtisanFilters } from "@/components/search/ArtisanFilters"
import { ArtisanCard } from "@/components/search/ArtisanCard"
import { useDebounce } from "@/hooks/useDebounce"
import api from "@/lib/api-client"
import { cn } from "@/lib/utils"

// Client-side only components
const ArtisanMap = dynamic(
  () => import('@/components/search/ArtisanMap').then(mod => mod.ArtisanMap),
  { ssr: false, loading: () => <div className="w-full h-full bg-slate-100 animate-pulse rounded-[40px]" /> }
)

export default function SearchPage() {
  const t = useTranslations("search")
  const common = useTranslations("common")
  const locale = useLocale()

  // State
  const [view, setView] = React.useState("grid") // grid | list | map
  const [isSidebarOpen, setIsSidebarOpen] = React.useState(false) // For mobile
  const [loading, setLoading] = React.useState(true)
  const [results, setResults] = React.useState({ data: [], total: 0, current_page: 1, last_page: 1 })
  const [categories, setCategories] = React.useState([])
  const [wilayas, setWilayas] = React.useState([])

  // Filters State
  const [searchTerm, setSearchTerm] = React.useState("")
  const debouncedSearch = useDebounce(searchTerm, 300)
  const [filters, setFilters] = React.useState({
    categories: [],
    wilaya_id: null,
    min_rating: 0,
    experience: null,
    available_only: false,
    lat: null,
    lng: null,
    sort: "relevance",
    geoError: false
  })

  // Effects
  React.useEffect(() => {
    fetchStaticData()
  }, [])

  React.useEffect(() => {
    fetchArtisans(1)
  }, [debouncedSearch, filters])

  const fetchStaticData = async () => {
    try {
      const [catRes, wilRes] = await Promise.all([
        api.get("/categories"),
        api.get("/wilayas")
      ])
      setCategories(catRes.data)
      setWilayas(wilRes.data)
    } catch (err) {
      console.error("Static data fetch failed", err)
    }
  }

  const fetchArtisans = async (page = 1) => {
    setLoading(true)
    try {
      const params = {
        q: debouncedSearch,
        categories: filters.categories,
        wilaya_id: filters.wilaya_id,
        min_rating: filters.min_rating,
        experience: filters.experience,
        available_only: filters.available_only ? 1 : 0,
        lat: filters.lat,
        lng: filters.lng,
        sort: filters.sort,
        page
      }
      const res = await api.get("/artisans", { params })
      setResults(res.data)
    } catch (err) {
      console.error("Search failed", err)
    } finally {
      setLoading(false)
    }
  }

  const handleGeoActivate = () => {
    if (!navigator.geolocation) {
       setFilters({ ...filters, geoError: true })
       return
    }

    navigator.geolocation.getCurrentPosition(
      (pos) => {
        setFilters({ 
          ...filters, 
          lat: pos.coords.latitude, 
          lng: pos.coords.longitude,
          geoError: false 
        })
      },
      () => setFilters({ ...filters, geoError: true })
    )
  }

  const handleReset = () => {
    setSearchTerm("")
    setFilters({
      categories: [],
      wilaya_id: null,
      min_rating: 0,
      experience: null,
      available_only: false,
      lat: null,
      lng: null,
      sort: "relevance",
      geoError: false
    })
  }

  return (
    <div className="max-w-[1440px] mx-auto px-4 md:px-8 py-10 min-h-screen">

      {/* Search Header */}
      <div className="flex flex-col lg:flex-row gap-6 items-center mb-10">
         <div className="w-full lg:flex-1 relative">
            <Search className="absolute left-6 top-1/2 -translate-y-1/2 w-6 h-6 text-slate-400" />
            <Input 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              placeholder={t("placeholder")}
              className="h-16 pl-16 pr-14 rounded-3xl bg-white dark:bg-slate-900 border-2 border-slate-100 dark:border-white/5 font-bold shadow-xl shadow-slate-100/30 dark:shadow-none focus:border-blue-500 transition-all text-lg"
            />
            {searchTerm && (
              <button 
                onClick={() => setSearchTerm("")}
                className="absolute right-6 top-1/2 -translate-y-1/2 p-2 hover:bg-slate-100 dark:hover:bg-white/10 rounded-full text-slate-400"
              >
                <X className="w-5 h-5" />
              </button>
            )}
         </div>

         <div className="flex p-2 bg-white dark:bg-slate-900 rounded-[30px] border-2 border-slate-100 dark:border-white/5 shadow-lg shrink-0 w-full lg:w-auto">
            {[
              { id: 'grid', icon: LayoutGrid, label: t("view_grid") },
              { id: 'list', icon: List, label: t("view_list") },
              { id: 'map', icon: MapIcon, label: t("view_map") }
            ].map((v) => (
              <button
                key={v.id}
                onClick={() => setView(v.id)}
                className={cn(
                  "flex-1 md:flex-none h-12 px-6 rounded-2xl flex items-center justify-center gap-2 font-black text-[10px] uppercase tracking-widest transition-all",
                  view === v.id ? "bg-slate-900 dark:bg-white text-white dark:text-slate-900 shadow-xl" : "text-slate-400 opacity-60 hover:opacity-100"
                )}
              >
                <v.icon className="w-4 h-4" />
                <span className="hidden md:inline">{v.label}</span>
              </button>
            ))}
         </div>
      </div>

      <div className="flex flex-col lg:flex-row gap-8">

        {/* Sidebar (Desktop) */}
        <aside className="hidden lg:block w-80 shrink-0">
           <ArtisanFilters 
             filters={filters}
             setFilters={setFilters}
             categories={categories}
             wilayas={wilayas}
             onReset={handleReset}
             onGeoActivate={handleGeoActivate}
           />
        </aside>

        {/* Results Area */}
        <main className="flex-1 space-y-8">

           {/* Results Meta */}
           <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
              <div className="space-y-1">
                 <h2 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">
                   {t("results_found", { count: results.total })}
                 </h2>
                 <p className="text-xs font-bold text-slate-500 opacity-80 italic">
                    {t("currently_available", { count: results.data.filter(a => a.disponibilite === 'disponible').length })}
                 </p>
              </div>

              <div className="flex items-center gap-3">
                 <select 
                   value={filters.sort}
                   onChange={(e) => setFilters({ ...filters, sort: e.target.value })}
                   className="h-10 bg-white dark:bg-slate-900 border border-slate-100 dark:border-white/5 rounded-xl px-4 text-[10px] font-black uppercase tracking-widest outline-none focus:border-blue-500"
                 >
                    <option value="relevance">{t("sort_relevance")}</option>
                    <option value="rating">{t("sort_rating")}</option>
                    <option value="experience">{t("sort_exp")}</option>
                    <option value="name">{t("sort_name")}</option>
                 </select>

                 <Button 
                   onClick={() => setIsSidebarOpen(true)}
                   variant="outline" 
                   className="lg:hidden h-10 rounded-xl px-3 border-slate-100 dark:border-white/5"
                 >
                    <FilterIcon className="w-4 h-4" />
                 </Button>
              </div>
           </div>

           {/* Mobile Filter Drawer Placeholder logic (using a Simple Panel for now) */}
           <AnimatePresence>
             {isSidebarOpen && (
               <motion.div 
                 initial={{ opacity: 0, x: 300 }}
                 animate={{ opacity: 1, x: 0 }}
                 exit={{ opacity: 0, x: 300 }}
                 className="fixed inset-0 z-[100] lg:hidden bg-white dark:bg-slate-950 p-6 overflow-y-auto"
               >
                 <div className="flex justify-between items-center mb-8">
                    <h2 className="text-xl font-black uppercase">{t("filters_title")}</h2>
                    <Button variant="ghost" size="icon" onClick={() => setIsSidebarOpen(false)}>
                       <X className="w-6 h-6" />
                    </Button>
                 </div>
                 <ArtisanFilters 
                    filters={filters}
                    setFilters={setFilters}
                    categories={categories}
                    wilayas={wilayas}
                    onReset={handleReset}
                    onGeoActivate={handleGeoActivate}
                 />
                 <Button className="w-full h-14 rounded-2xl bg-blue-600 font-black uppercase tracking-widest" onClick={() => setIsSidebarOpen(false)}>
                    Appliquer
                 </Button>
               </motion.div>
             )}
           </AnimatePresence>

           {/* Views Container */}
           <div className="relative min-h-[600px]">
              {loading ? (
                <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
                   {[1,2,3,4,5,6].map(i => (
                     <div key={i} className="h-[400px] bg-slate-50 dark:bg-slate-900 animate-pulse rounded-[40px] border border-slate-100 dark:border-white/5" />
                   ))}
                </div>
              ) : results.data.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-20 text-center space-y-6">
                   <div className="w-24 h-24 bg-slate-50 dark:bg-slate-900 rounded-full flex items-center justify-center text-slate-300">
                      <AlertCircle className="w-12 h-12" />
                   </div>
                   <div>
                      <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase">{t("no_results")}</h3>
                      <p className="text-sm font-bold text-slate-500 mt-1">{t("no_results_hint")}</p>
                   </div>
                   <Button onClick={handleReset} className="rounded-full px-8 bg-blue-600 font-black uppercase text-[10px] tracking-widest h-12">
                      {t("reset_filters")}
                   </Button>
                </div>
              ) : view === 'grid' ? (
                <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
                   {results.data.map(artisan => (
                     <ArtisanCard key={artisan.id} artisan={artisan} view="grid" />
                   ))}
                </div>
              ) : view === 'list' ? (
                <div className="space-y-4">
                   {results.data.map(artisan => (
                     <ArtisanCard key={artisan.id} artisan={artisan} view="list" />
                   ))}
                </div>
              ) : (
                <div className="h-[70vh] sticky top-20">
                   <ArtisanMap artisans={results.data} userCoords={filters.lat ? { lat: filters.lat, lng: filters.lng } : null} />
                </div>
              )}
           </div>

           {/* Pagination */}
           {results.last_page > 1 && !loading && view !== 'map' && (
              <div className="flex items-center justify-center gap-4 py-10">
                 <Button 
                   disabled={results.current_page === 1}
                   onClick={() => fetchArtisans(results.current_page - 1)}
                   variant="outline"
                   className="h-12 w-12 rounded-2xl border-slate-100 dark:border-white/5 bg-white dark:bg-slate-900"
                 >
                    <ChevronLeft className="w-5 h-5" />
                 </Button>

                 <div className="flex gap-2">
                    {[...Array(results.last_page)].map((_, i) => (
                       <button
                         key={i}
                         onClick={() => fetchArtisans(i + 1)}
                         className={cn(
                           "w-12 h-12 rounded-2xl text-xs font-black transition-all",
                           results.current_page === i + 1 
                             ? "bg-slate-900 dark:bg-white text-white dark:text-slate-900 shadow-xl" 
                             : "bg-white dark:bg-slate-900 text-slate-400 hover:bg-slate-50 dark:hover:bg-white/5"
                         )}
                       >
                          {i + 1}
                       </button>
                    ))}
                 </div>

                 <Button 
                   disabled={results.current_page === results.last_page}
                   onClick={() => fetchArtisans(results.current_page + 1)}
                   variant="outline"
                   className="h-12 w-12 rounded-2xl border-slate-100 dark:border-white/5 bg-white dark:bg-slate-900"
                 >
                    <ChevronRight className="w-5 h-5" />
                 </Button>
              </div>
           )}

        </main>
      </div>
    </div>
  )
}

"use client"

import * as React from "react"
import { motion } from "framer-motion"
import {
  Users, Briefcase, ClipboardList, TrendingUp,
  RefreshCw, ShieldCheck, AlertTriangle, CheckCircle2
} from "lucide-react"
import { useTranslations, useLocale } from "next-intl"
import { useAdminOverview } from "@/hooks/useAdminOverview"
import { KpiCard } from "@/components/admin/KpiCard"
import { AdminAlerts } from "@/components/admin/AdminAlerts"
import { RegistrationsChart, WilayaBarChart } from "@/components/admin/AdminCharts"
import { ActivityFeed } from "@/components/admin/ActivityFeed"
import { useAuth } from "@/context/AuthContext"
import { cn } from "@/lib/utils"

/* ─────────────────────────── ICON MAP ──────────────────────────── */
const ICON_MAP = {
  Users,
  Briefcase,
  ClipboardList,
  TrendingUp,
}

/* ─────────────────────── KPI SKELETON CARD ─────────────────────── */
function KpiSkeleton() {
  return (
    <div className="bg-white dark:bg-slate-900 rounded-[32px] p-6 border border-slate-100 dark:border-white/5 shadow-xl animate-pulse">
      <div className="flex items-start justify-between mb-4">
        <div className="w-12 h-12 rounded-2xl bg-slate-100 dark:bg-white/5" />
        <div className="w-16 h-6 rounded-full bg-slate-100 dark:bg-white/5" />
      </div>
      <div className="space-y-2">
        <div className="h-2 w-24 rounded bg-slate-100 dark:bg-white/5" />
        <div className="h-8 w-32 rounded bg-slate-100 dark:bg-white/5" />
        <div className="h-2 w-20 rounded bg-slate-100 dark:bg-white/5" />
      </div>
    </div>
  )
}

/* ────────────────────── CHART SKELETON ─────────────────────────── */
function ChartSkeleton({ height = 320 }) {
  return (
    <div
      className="bg-white dark:bg-slate-900 rounded-[32px] border border-slate-100 dark:border-white/5 p-6 shadow-xl animate-pulse"
      style={{ minHeight: height }}
    >
      <div className="h-2 w-24 rounded bg-slate-100 dark:bg-white/5 mb-2" />
      <div className="h-5 w-48 rounded bg-slate-100 dark:bg-white/5 mb-6" />
      <div className="space-y-3">
        {Array.from({ length: 6 }).map((_, i) => (
          <div key={i} className="flex items-end gap-2">
            <div
              className="w-full rounded bg-slate-100 dark:bg-white/5"
              style={{ height: `${20 + Math.random() * 80}px` }}
            />
          </div>
        ))}
      </div>
    </div>
  )
}

/* ──────────────────────── ALERTS SKELETON ───────────────────────── */
function AlertsSkeleton() {
  return (
    <div className="animate-pulse space-y-3">
      <div className="h-3 w-32 rounded bg-slate-100 dark:bg-white/5" />
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
        {[1, 2, 3].map((i) => (
          <div
            key={i}
            className="h-20 rounded-[24px] bg-slate-100 dark:bg-white/5"
          />
        ))}
      </div>
    </div>
  )
}

/* ──────────────────────── ACTIVITY SKELETON ─────────────────────── */
function ActivitySkeleton() {
  return (
    <div className="bg-white dark:bg-slate-900 rounded-[32px] border border-slate-100 dark:border-white/5 p-6 shadow-xl animate-pulse">
      <div className="h-2 w-20 rounded bg-slate-100 dark:bg-white/5 mb-2" />
      <div className="h-5 w-40 rounded bg-slate-100 dark:bg-white/5 mb-6" />
      <div className="space-y-5 pl-5">
        {Array.from({ length: 5 }).map((_, i) => (
          <div key={i} className="flex items-start gap-4">
            <div className="w-8 h-8 rounded-xl bg-slate-100 dark:bg-white/5 shrink-0" />
            <div className="flex-1 space-y-2">
              <div className="h-3 w-3/4 rounded bg-slate-100 dark:bg-white/5" />
              <div className="h-2 w-1/3 rounded bg-slate-100 dark:bg-white/5" />
            </div>
          </div>
        ))}
      </div>
    </div>
  )
}

