                       <AnimatePresence>
                          {isSelected && (
                             <motion.div 
                               initial={{ scale: 0 }}
                               animate={{ scale: 1 }}
                               className="absolute top-3 right-3 w-5 h-5 bg-blue-600 rounded-full flex items-center justify-center text-white border-2 border-white dark:border-slate-950 shadow-lg"
