"use client"

import * as React from "react"
import { useTranslations, useLocale } from "next-intl"
import { 
  X, 
  Search, 
  UserPlus, 
  Check, 
  ChevronRight,
  Info 
} from "lucide-react"
import { Button } from "@/components/ui/Button"
