export function ManualActivationModal({ isOpen, onClose, onActivate, artisans }) {
  const t = useTranslations("admin.subscription_management.manual_activation")
  const locale = useLocale()
  const [search, setSearch] = React.useState("")
  const [selectedArtisan, setSelectedArtisan] = React.useState(null)
  const [formData, setFormData] = React.useState({
    plan: "mensuel",
    amount: 1000,
    notes: ""
  })

  const filteredArtisans = search?.length > 1 
    ? artisans.filter(a => a.user?.nomComplet?.toLowerCase().includes(search.toLowerCase()))
    : []

  const handleActivate = () => {
    if (!selectedArtisan) return
    onActivate({
      artisan_id: selectedArtisan.id,
      ...formData
    })
  }

  const plans = [
    { id: "mensuel", label: "Pro Mensuel (1 mois)", price: 1000 },
    { id: "trimestriel", label: "Pro Trimestriel (3 mois)", price: 3000 },
    { id: "annuel", label: "Elite Annuel (12 mois)", price: 10000 }
  ]

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={t("title")}>
      <div className="space-y-6">
        {/* Step 1: Artisan Selection */}
        {!selectedArtisan ? (
          <div className="space-y-4">
            <label className="text-sm font-bold text-slate-700 dark:text-slate-300">
              {t("search_artisan")}
            </label>
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <Input 
                value={search}
                onChange={e => setSearch(e.target.value)}
                placeholder="Ex: Mohamed..."
                className="pl-10"
              />
            </div>
            <div className="max-h-60 overflow-y-auto space-y-2 pr-2">
              {filteredArtisans.map(artisan => (
                <button
                  key={artisan.id}
                  onClick={() => setSelectedArtisan(artisan)}
                  className="w-full flex items-center justify-between p-3 rounded-2xl border border-slate-100 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
                >
                  <div className="flex items-center gap-3">
                    <Avatar 
                      src={artisan.photo} 
                      className="w-10 h-10 rounded-xl"
                      initials={artisan.user?.nomComplet?.charAt(0)}
                    />
                    <div className="flex flex-col text-left rtl:text-right">
                      <span className="font-bold text-slate-900 dark:text-white leading-tight">
                        {artisan.user?.nomComplet}
                      </span>
                      <span className="text-[10px] uppercase font-bold text-slate-400">
                         {artisan.telephone}
                      </span>
                    </div>
                  </div>
                  <ChevronRight className="w-4 h-4 text-slate-300" />
                </button>
              ))}
              {search.length > 2 && filteredArtisans.length === 0 && (
                <p className="text-center text-sm text-slate-500 py-4">
                   Aucun artisan correspondant trouvé.
                </p>
              )}
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            {/* Step 2: Plan & Payment Details */}
            <div className="flex items-center justify-between bg-blue-50 dark:bg-blue-500/10 p-4 rounded-2xl border border-blue-100 dark:border-blue-900/40">
              <div className="flex items-center gap-3">
                <Avatar 
                  src={selectedArtisan.photo} 
                  className="w-12 h-12 rounded-2xl"
                  initials={selectedArtisan.user?.nomComplet?.charAt(0)}
                />
                <div className="flex flex-col">
                   <span className="font-black text-blue-700 dark:text-blue-400">
                     {selectedArtisan.user?.nomComplet}
                   </span>
                   <span className="text-xs text-blue-600 dark:text-blue-500 font-medium tracking-tight">
                      {selectedArtisan.telephone}
                   </span>
                </div>
              </div>
              <button 
                onClick={() => setSelectedArtisan(null)}
                className="text-xs font-bold text-blue-700 dark:text-blue-400 hover:underline"
              >
                Changer
              </button>
            </div>

            <div className="space-y-4">
               <div className="space-y-2">
                 <label className="text-sm font-bold text-slate-700 dark:text-slate-300">{t("select_plan")}</label>
                 <select
                   className="w-full h-12 rounded-xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 px-4 focus:ring-2 focus:ring-blue-500"
                   value={formData.plan}
                   onChange={e => {
                     const plan = plans.find(p => p.id === e.target.value)
                     setFormData({ ...formData, plan: e.target.value, amount: plan.price })
                   }}
                 >
                   {plans.map(p => (
                     <option key={p.id} value={p.id}>{p.label}</option>
                   ))}
                 </select>
               </div>

               <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-sm font-bold text-slate-700 dark:text-slate-300">{t("amount_label")}</label>
                    <Input 
                       type="number" 
                       value={formData.amount} 
                       onChange={e => setFormData({ ...formData, amount: e.target.value })}
                     />
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-bold text-slate-700 dark:text-slate-300">{t("method_label")}</label>
                    <Select defaultValue="espéces">
                       <option value="espéces">Espèces</option>
                       <option value="virement">Virement (CCP/CCP)</option>
                       <option value="autre">Autre</option>
                    </Select>
                  </div>
               </div>

               <div className="space-y-2">
                 <label className="text-sm font-bold text-slate-700 dark:text-slate-300">Notes d'administration</label>
                 <textarea 
                   className="w-full h-24 p-4 rounded-xl bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 resize-none focus:ring-2 focus:ring-blue-500"
                   placeholder="Ex: Paiement reçu en agence..."
                   value={formData.notes}
                   onChange={e => setFormData({ ...formData, notes: e.target.value })}
                 />
               </div>
            </div>

            <div className="flex gap-3 pt-4">
               <Button variant="outline" className="grow rounded-xl h-12" onClick={onClose}>
                 {t("modals.cancel_btn")}
               </Button>
               <Button className="grow rounded-xl h-12 shadow-xl shadow-blue-500/20" onClick={handleActivate}>
                 <Check className="w-5 h-5 mr-2" />
                 {t("btn")}
               </Button>
            </div>
          </div>
        )}
      </div>
    </Modal>
  )
}

'use client';

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Users, 
  Search, 
  Filter, 
  Mail, 
  Ban, 
  Download, 
  Plus, 
  RefreshCcw,
  CheckCircle2,
  AlertCircle
} from 'lucide-react';
import { useTranslations } from 'next-intl';
import { UserTable } from './UserTable';
import { ComposeEmailModal, SuspendUserModal, DeleteUserModal } from './UserActionModals';
import api from '@/lib/axios';
import { useToastStore } from '@/store/toastStore';

const AdminUserManagement = () => {
  const t = useTranslations('admin.user_management');
  const commonT = useTranslations('common');
  const addToast = useToastStore((state) => state.addToast);
  const showToast = (msg, type = 'success') => addToast({ title: msg, type });

  const [activeTab, setActiveTab] = useState('clients');
  const [loading, setLoading] = useState(true);
  const [users, setUsers] = useState([]);
  const [pagination, setPagination] = useState({ current: 1, total: 1 });

  // Filters
  const [search, setSearch] = useState('');
  const [status, setStatus] = useState('');
  const [wilayaId, setWilayaId] = useState('');

  // Selection
  const [selectedUsers, setSelectedUsers] = useState([]);

  // Modals state
  const [modalType, setModalType] = useState(null); // 'email', 'suspend', 'delete', 'bulk_email', 'bulk_suspend'
  const [currentUser, setCurrentUser] = useState(null);

  const fetchUsers = useCallback(async (page = 1) => {
    setLoading(true);
    try {
      const endpoint = activeTab === 'clients' ? '/admin/users/clients' : '/admin/users/artisans';
      const response = await api.get(endpoint, {
        params: {
          page,
          search,
          status: status || undefined,
          wilaya_id: wilayaId || undefined,
        }
      });

      setUsers(response.data.data || []);
      setPagination({
        current: response.data.current_page,
        total: response.data.last_page
      });
    } catch (error) {
      console.error('Error fetching users:', error);
      showToast(commonT('error'), 'error');
    } finally {
      setLoading(false);
    }
  }, [activeTab, search, status, wilayaId, commonT]);

  useEffect(() => {
    fetchUsers(1);
    setSelectedUsers([]);
  }, [fetchUsers]);

  const handleSelectUser = (id) => {
    setSelectedUsers(prev => 
      prev.includes(id) ? prev.filter(uid => uid !== id) : [...prev, id]
    );
  };

  const handleSelectAll = () => {
    if (selectedUsers.length === users.length) {
      setSelectedUsers([]);
    } else {
      setSelectedUsers(users.map(u => u.user?.id || u.id));
    }
  };

  const handleAction = (type, user) => {
    setCurrentUser(user);
    setModalType(type);
  };

  const executeAction = async (data) => {
    try {
      const userId = currentUser.user?.id || currentUser.id;
      let response;

      switch (modalType) {
        case 'email':
          response = await api.post('/admin/users/email', {
            user_id: userId,
            subject: data.subject,
            message: data.message
          });
          showToast(t('notifications.email_sent'));
          break;

        case 'suspend':
          // We can use the existing updateArtisanStatus for artisans or a new general one
          // For now let's use our new controller endpoint if we have it or a generic one
          response = await api.post(`/admin/artisans/${userId}/status`, {
            statut: currentUser.user?.statut === 'actif' ? 'suspendu' : 'actif',
            reason: data
          });
          showToast(currentUser.user?.statut === 'actif' ? t('notifications.user_suspended') : t('notifications.user_unsuspended'));
          fetchUsers(pagination.current);
          break;

        case 'delete':
          response = await api.post(`/admin/users/${userId}/delete`, {
            reason: data
          });
          showToast(t('notifications.user_deleted'));
          fetchUsers(pagination.current);
          break;

        case 'bulk_email':
          response = await api.post('/admin/users/bulk', {
            user_ids: selectedUsers,
            type: 'email',
            subject: data.subject,
            message: data.message
          });
          showToast(t('notifications.bulk_success'));
          setSelectedUsers([]);
          break;

        case 'bulk_suspend':
          response = await api.post('/admin/users/bulk', {
            user_ids: selectedUsers,
            type: 'suspend',
            message: data
          });
          showToast(t('notifications.bulk_success'));
          setSelectedUsers([]);
          fetchUsers(pagination.current);
          break;
      }
    } catch (error) {
      showToast(error.response?.data?.message || commonT('error'), 'error');
    }
  };

  return (
    <div className="space-y-6">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm">
        <div>
          <h1 className="text-2xl font-black text-slate-900 dark:text-white flex items-center gap-3">
            <Users className="text-blue-600" size={28} />
            {t('title')}
          </h1>
          <p className="text-slate-500 dark:text-slate-400 mt-1 max-w-xl">
            {t('subtitle')}
          </p>
        </div>

        <div className="flex items-center gap-2">
          <button className="flex items-center gap-2 px-4 py-2 bg-slate-50 dark:bg-slate-800 text-slate-700 dark:text-slate-300 rounded-xl hover:bg-slate-100 transition-colors border border-slate-100 dark:border-slate-700 font-bold text-sm">
            <Download size={18} />
            Exporter CSV
          </button>
        </div>
      </div>

      {/* Tabs & Filters */}
      <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm overflow-hidden">
        <div className="flex flex-col lg:flex-row lg:items-center justify-between border-b border-slate-100 dark:border-slate-800 p-4 gap-4">
          {/* Tabs */}
          <div className="flex p-1.5 bg-slate-100 dark:bg-slate-800 rounded-2xl w-fit">
            <button
              onClick={() => setActiveTab('clients')}
              className={`px-6 py-2.5 rounded-xl font-bold transition-all text-sm flex items-center gap-2 ${
                activeTab === 'clients' 
