export default function RegisterForm() {
  const { register, loginWithGoogle } = useAuth();
  const [role, setRole] = useState("client");
  const [form, setForm] = useState({ name: "", email: "", password: "", password_confirmation: "", telephone: "" });
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState(null);
  const [fieldErrors, setFieldErrors] = useState({});
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    setForm((prev) => ({ ...prev, [e.target.name]: e.target.value }));
    if (fieldErrors[e.target.name]) {
      setFieldErrors(prev => ({ ...prev, [e.target.name]: null }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (loading) return; // prevent double submit
    setError(null);
    setFieldErrors({});

    // JS-side Algerian phone validation
    const phoneRegex = /^0(5|6|7)\d{8}$/;
    if (!phoneRegex.test(form.telephone)) {
      setFieldErrors(prev => ({
        ...prev,
        telephone: "Format invalide. Utilisez 05/06/07 suivi de 8 chiffres."
      }));
      setError("Veuillez corriger les erreurs ci-dessous.");
      return;
    }

    setLoading(true);
    try {
      await register({ ...form, type: role });
    } catch (err) {
      if (err.status === 422 && err.errors) {
        setFieldErrors(err.errors);
        setError("Veuillez corriger les erreurs ci-dessous.");
      } else {
        setError(
          err.response?.data?.message || err.message || "Une erreur est survenue lors de l'inscription."
        );
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <motion.div 
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5 }}
      className="glass rounded-[32px] shadow-2xl p-8 md:p-12 relative overflow-hidden"
    >
      <div className="absolute top-0 left-0 right-0 h-1.5 bg-gradient-to-r from-blue-500 to-indigo-600" />

      <div className="text-center mb-8">
        <div className="inline-flex items-center justify-center w-14 h-14 rounded-2xl bg-blue-50 text-blue-600 mb-4">
          <UserPlus size={28} />
        </div>
        <h1 className="text-3xl font-extrabold text-gray-900 tracking-tight">Créer un compte</h1>
        <p className="text-gray-500 mt-2 font-medium">Rejoignez la communauté DzArtisan dès aujourd'hui</p>
      </div>

      <div className="bg-gray-100 p-1 rounded-xl flex mb-8">
        <button
          onClick={() => setRole("client")}
          className={`cursor-pointer flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg text-sm font-semibold transition-all duration-200 ${
            role === "client" ? "bg-white text-blue-600 shadow-sm" : "text-gray-500 hover:text-gray-700"
          }`}
        >
          <User size={16} />
          Client
        </button>
        <button
          onClick={() => setRole("artisan")}
          className={`cursor-pointer flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg text-sm font-semibold transition-all duration-200 ${
            role === "artisan" ? "bg-white text-blue-600 shadow-sm" : "text-gray-500 hover:text-gray-700"
          }`}
        >
          <Wrench size={16} />
          Artisan
        </button>
      </div>

      {error && (
        <motion.div 
          initial={{ opacity: 0, x: -10 }}
          animate={{ opacity: 1, x: 0 }}
          className="mb-6 rounded-xl bg-red-50 border border-red-100 px-4 py-3 text-sm text-red-600 font-medium"
        >
          {error}
        </motion.div>
      )}

      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-bold text-gray-700 mb-2 ml-1">Nom complet</label>
          <div className="relative group">
            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-blue-600 transition-colors">
              <User size={18} />
            </div>
            <input
              type="text"
              name="name"
              value={form.name}
              onChange={handleChange}
              required
              placeholder="Prénom Nom"
              className={`w-full bg-white rounded-xl border ${fieldErrors.name ? 'border-red-500' : 'border-gray-200'} pl-11 pr-4 py-3.5 text-sm outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all placeholder:text-gray-300`}
            />
          </div>
          {fieldErrors.name && <p className="text-red-500 text-xs mt-1 ml-2">{fieldErrors.name}</p>}
        </div>

        <div>
           <label className="block text-sm font-bold text-gray-700 mb-2 ml-1">Téléphone</label>
           <div className="relative group">
             <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-blue-600 transition-colors">
               <span className="text-sm font-bold">+213</span>
             </div>
             <input
               type="text"
               name="telephone"
               value={form.telephone}
               onChange={handleChange}
               required
               placeholder="05 55 55 55 55"
               pattern="^0[567][0-9]{8}$"
               title="Format algérien: 05, 06 ou 07 suivi de 8 chiffres"
               className={`w-full bg-white rounded-xl border ${fieldErrors.telephone ? 'border-red-500' : 'border-gray-200'} pl-14 pr-4 py-3.5 text-sm outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all placeholder:text-gray-300`}
             />
           </div>
           {fieldErrors.telephone && <p className="text-red-500 text-xs mt-1 ml-2">{fieldErrors.telephone}</p>}
        </div>

        <div>
          <label className="block text-sm font-bold text-gray-700 mb-2 ml-1">Adresse e-mail</label>
          <div className="relative group">
            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-blue-600 transition-colors">
              <Mail size={18} />
            </div>
            <input
              type="email"
              name="email"
              value={form.email}
              onChange={handleChange}
              required
              placeholder="example@email.com"
              className={`w-full bg-white rounded-xl border ${fieldErrors.email ? 'border-red-500' : 'border-gray-200'} pl-11 pr-4 py-3.5 text-sm outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all placeholder:text-gray-300`}
            />
          </div>
          {fieldErrors.email && <p className="text-red-500 text-xs mt-1 ml-2">{fieldErrors.email}</p>}
        </div>

        <div>
          <label className="block text-sm font-bold text-gray-700 mb-2 ml-1">Mot de passe</label>
          <div className="relative group">
            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-blue-600 transition-colors">
              <Lock size={18} />
            </div>
            <input
              type={showPassword ? "text" : "password"}
              name="password"
              value={form.password}
              onChange={handleChange}
              required
              placeholder="Min. 8 caractères"
              className={`w-full bg-white rounded-xl border ${fieldErrors.password ? 'border-red-500' : 'border-gray-200'} pl-11 pr-11 py-3.5 text-sm outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all placeholder:text-gray-300`}
            />
            <button
              type="button"
              onClick={() => setShowPassword(!showPassword)}
              className="absolute inset-y-0 right-0 pr-4 flex items-center text-gray-400 hover:text-gray-600 transition-colors"
            >
              {!showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
            </button>
          </div>
          {fieldErrors.password && <p className="text-red-500 text-xs mt-1 ml-2">{fieldErrors.password}</p>}
        </div>

        <div>
          <label className="block text-sm font-bold text-gray-700 mb-2 ml-1">Confirmer le mot de passe</label>
          <div className="relative group">
            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-400 group-focus-within:text-blue-600 transition-colors">
              <Lock size={18} />
            </div>
            <input
              type={showPassword ? "text" : "password"}
              name="password_confirmation"
              value={form.password_confirmation}
              onChange={handleChange}
              required
              placeholder="Répétez votre mot de passe"
              className="w-full bg-white rounded-xl border border-gray-200 pl-11 pr-11 py-3.5 text-sm outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all placeholder:text-gray-300"
            />
          </div>
        </div>

        <div className="flex items-start gap-3 ml-1 mb-6">
          <input
            id="terms"
            type="checkbox"
            required
            className="mt-1 w-4 h-4 text-blue-600 bg-gray-100 border-gray-300 rounded focus:ring-blue-500"
          />
          <label htmlFor="terms" className="text-xs font-semibold text-gray-500 leading-relaxed">
            J'accepte les <a href="#" className="text-blue-600 link-premium">Conditions d'utilisation</a> et la <a href="#" className="text-blue-600 link-premium">Politique de confidentialité</a>
          </label>
        </div>

        <button
          type="submit"
          disabled={loading || form.password !== form.password_confirmation}
          className="w-full relative flex items-center justify-center gap-2 rounded-xl bg-blue-600 hover:bg-blue-700 disabled:opacity-70 text-white text-sm font-bold py-4 shadow-lg shadow-blue-500/25 transition-all group active:scale-[0.98]"
        >
          {loading ? "Création..." : "Créer mon compte"}
          {!loading && <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" /> }
        </button>
      </form>

      {role === "client" && (
        <>
          <div className="relative flex items-center gap-4 my-8">
            <div className="flex-1 h-px bg-gray-100" />
            <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Ou s'inscrire avec</span>
            <div className="flex-1 h-px bg-gray-100" />
          </div>

          <button
            onClick={loginWithGoogle}
            className="w-full flex items-center justify-center gap-3 rounded-xl border border-gray-200 bg-white hover:bg-gray-50 px-4 py-3.5 text-sm font-bold text-gray-700 transition-all active:scale-[0.98]"
          >
            <svg width="20" height="20" viewBox="0 0 48 48">
              <path d="M43.6 20.5H42V20H24v8h11.3C33.7 32.7 29.2 36 24 36c-6.6 0-12-5.4-12-12s5.4-12 12-12c3.1 0 5.8 1.1 7.9 3l5.7-5.7C34.5 6.5 29.5 4 24 4 12.9 4 4 12.9 4 24s8.9 20 20 20 20-8.9 20-20c0-1.2-.1-2.5-.4-3.5z" fill="#FFC107" />
              <path d="M6.3 14.7l6.6 4.8C14.7 16 19 13 24 13c3.1 0 5.8 1.1 7.9 3l5.7-5.7C34.5 6.5 29.5 4 24 4 16.3 4 9.7 8.3 6.3 14.7z" fill="#FF3D00" />
              <path d="M24 44c5.3 0 10.2-2 13.8-5.3l-6.4-5.4C29.4 35 26.8 36 24 36c-5.2 0-9.6-3.3-11.2-8H6.2C9.5 35.6 16.2 44 24 44z" fill="#4CAF50" />
              <path d="M43.6 20.5H42V20H24v8h11.3c-.8 2.2-2.2 4.1-4.1 5.4l6.4 5.4C37.4 39.2 44 34 44 24c0-1.2-.1-2.5-.4-3.5z" fill="#1976D2" />
            </svg>
            Continuer avec Google
          </button>
        </>
      )}

      <p className="mt-8 text-center text-sm font-semibold text-gray-500">
        Déjà un compte ?{" "}
        <a href="/login" className="text-blue-600 font-bold link-premium">Se connecter</a>
      </p>
    </motion.div>
  );
}

'use client';

import React, { useState } from 'react';
import { 
  X, Phone, MessageSquare, MapPin, 
  Trash2, Plus, CheckCircle2, ShieldCheck, 
  Map as MapIcon, Image as ImageIcon,
  Loader2,
  Trash
} from 'lucide-react';
import { useTranslations, useLocale } from 'next-intl';
import { Button } from '@/components/ui/Button';
import { motion, AnimatePresence } from 'framer-motion';
import axios from '@/lib/axios';
import { cn } from '@/lib/utils';

export const InterventionDetail = ({ isOpen, onClose, intervention, onPhotoUpdate }) => {
  const t = useTranslations('artisan.interventions');
  const locale = useLocale();
  const isRTL = locale === 'ar';

  const [uploading, setUploading] = useState(false);
  const [deleting, setDeleting] = useState(null);

  const handleFileUpload = async (event, type) => {
    const file = event.target.files[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('photo', file);
    formData.append('type', type);

    try {
      setUploading(true);
      const res = await axios.post(`/api/artisan/interventions/${intervention.id}/photo`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      onPhotoUpdate(res.data);
    } catch (err) {
      console.error('Upload error:', err);
    } finally {
      setUploading(false);
    }
  };

  const handleDeletePhoto = async (photoId) => {
    try {
      setDeleting(photoId);
      await axios.delete(`/api/artisan/interventions/${intervention.id}/photo/${photoId}`);
      onPhotoUpdate({ id: photoId, deleted: true });
    } catch (err) {
      console.error('Delete error:', err);
    } finally {
      setDeleting(null);
    }
  };

  if (!isOpen) return null;

  const photosBefore = intervention.photos?.filter(p => p.type === 'avant') || [];
  const photosAfter = intervention.photos?.filter(p => p.type === 'apres') || [];

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-[110] flex items-center justify-center p-0 md:p-4">
        {/* Backdrop */}
        <motion.div 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={onClose}
          className="absolute inset-0 bg-slate-900/80 backdrop-blur-md"
        />

        {/* Modal Content */}
        <motion.div 
          initial={{ opacity: 0, scale: 0.95, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.95, y: 20 }}
          className="relative w-full h-full md:h-auto md:max-w-4xl bg-white dark:bg-[#0a0f1e] md:rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row"
          dir={isRTL ? 'rtl' : 'ltr'}
        >
          {/* Header (Mobile Close) */}
          <div className="flex md:hidden items-center justify-between p-6 bg-white dark:bg-slate-900 border-b border-gray-100 dark:border-gray-800">
             <h3 className="font-black text-gray-900 dark:text-white uppercase tracking-widest">{t('details.title')}</h3>
             <button onClick={onClose} className="p-2 bg-slate-100 dark:bg-slate-800 rounded-xl">
               <X className="w-5 h-5 text-gray-500" />
             </button>
          </div>

          {/* Sidebar: Info & Actions (L/R based on RTL) */}
          <div className="w-full md:w-80 bg-slate-50 dark:bg-slate-900/50 p-8 border-r border-gray-100 dark:border-gray-800 flex flex-col gap-8">
             {/* Client Card */}
             <div className="space-y-4">
               <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{t('details.client_info')}</label>
               <div className="bg-white dark:bg-slate-800 p-5 rounded-3xl border border-gray-100 dark:border-gray-700/50 shadow-sm">
                  <div className="flex items-center gap-3 mb-4">
                    <div className="w-10 h-10 bg-primary-50 dark:bg-primary-900/20 rounded-xl flex items-center justify-center font-black text-primary-600">
                      {intervention.client?.user?.nomComplet?.charAt(0).toUpperCase()}
                    </div>
                    <div>
                      <h4 className="font-black text-gray-900 dark:text-white leading-tight">
                        {intervention.client?.user?.nomComplet}
                      </h4>
                      <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                        {intervention.client?.user?.telephone || '+213 6 XX XX XX XX'}
                      </p>
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-2">
                    <Button variant="outline" size="sm" className="rounded-xl h-10 border-emerald-100 text-emerald-600 hover:bg-emerald-50 dark:border-emerald-900/30">
                       <MessageSquare className="w-4 h-4 mr-2 fill-current" /> WhatsApp
                    </Button>
                    <Button variant="outline" size="sm" className="rounded-xl h-10 border-blue-100 text-blue-600 hover:bg-blue-50 dark:border-blue-900/30">
                       <Phone className="w-4 h-4 mr-2" /> {t('details.contact_client').split(' ')[0]}
                    </Button>
                  </div>
               </div>
             </div>

             {/* Location Brief */}
             <div className="space-y-4">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{t('card.location').split(':')[0]}</label>
                <div className="flex items-start gap-3 px-1">
                   <div className="p-2 bg-blue-50 dark:bg-blue-900/20 rounded-xl">
                      <MapPin className="w-5 h-5 text-blue-600" />
                   </div>
                   <p className="text-sm font-bold text-gray-700 dark:text-gray-300">
                      {intervention.adresse || `${intervention.wilaya?.nom}, ${intervention.commune?.nom}`}
                   </p>
                </div>
             </div>

             {/* Progress Info */}
             <div className="space-y-4 mt-auto">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{t('details.progress')}</label>
                <div className="bg-primary-500 text-white p-5 rounded-3xl shadow-lg shadow-primary-500/20 flex items-center gap-4">
                   <ShieldCheck className="w-8 h-8 opacity-50" />
                   <div>
                     <h4 className="font-black text-sm uppercase tracking-widest">{t(`status.${intervention.statut}`)}</h4>
                     <p className="text-[10px] font-bold opacity-80">Projet en gestion sécurisée</p>
                   </div>
                </div>
             </div>
          </div>

          {/* Main Area: Photos & Gallery */}
          <div className="flex-1 p-8 md:p-12 overflow-y-auto space-y-12">
             <div className="flex items-center justify-between">
                <h2 className="text-3xl font-black text-gray-900 dark:text-white leading-tight">
                  {intervention.titre}
                </h2>
                <button onClick={onClose} className="hidden md:block p-3 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-2xl transition-colors">
                  <X className="w-6 h-6 text-gray-400" />
                </button>
             </div>

             {/* Description Card */}
             <div className="bg-white dark:bg-slate-800 p-6 rounded-3xl border border-gray-100 dark:border-gray-800 shadow-sm">
                <p className="text-gray-600 dark:text-gray-300 leading-relaxed font-medium">
                  {intervention.description}
                </p>
             </div>

             {/* Photos Section */}
             <div className="space-y-8">
               <div className="flex items-center justify-between border-b border-gray-100 dark:border-gray-800 pb-4">
                  <h3 className="text-xl font-black text-gray-900 dark:text-white tracking-widest uppercase flex items-center gap-3">
                    <ImageIcon className="w-6 h-6 text-primary-500" />
                    {t('details.photos_title')}
                  </h3>
                  {uploading && <Loader2 className="w-5 h-5 text-primary-500 animate-spin" />}
               </div>

               {/* Before Photos */}
               <div className="space-y-4">
                  <div className="flex items-center justify-between">
                     <span className="text-xs font-black text-slate-400 uppercase tracking-widest">{t('details.photo_before')}</span>
                     <label className="cursor-pointer">
                        <input type="file" className="hidden" accept="image/*" onChange={(e) => handleFileUpload(e, 'avant')} />
                        <div className="flex items-center gap-1 text-[10px] font-black text-primary-600 hover:text-primary-700 uppercase tracking-widest bg-primary-50 dark:bg-primary-900/20 px-3 py-1.5 rounded-xl transition-all">
                           <Plus className="w-3.5 h-3.5" />
                           {t('details.add_photo')}
                        </div>
                     </label>
                  </div>
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                     {photosBefore.map(photo => (
                        <div key={photo.id} className="aspect-square rounded-2xl overflow-hidden relative group border border-gray-100 dark:border-gray-800 shadow-sm">
                           <img src={photo.url} alt="Before" className="w-full h-full object-cover transition-transform group-hover:scale-110" />
                           <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                              <button 
                                onClick={() => handleDeletePhoto(photo.id)}
                                className="p-2 bg-red-500 text-white rounded-xl shadow-lg hover:bg-red-600 transition-colors"
                              >
                                {deleting === photo.id ? <Loader2 className="w-4 h-4 animate-spin" /> : <Trash2 className="w-4 h-4" />}
                              </button>
                           </div>
                        </div>
                     ))}
                     {photosBefore.length === 0 && (
                        <div className="aspect-square rounded-2xl bg-slate-50 dark:bg-slate-800/50 border-2 border-dashed border-slate-200 dark:border-slate-700 flex flex-col items-center justify-center text-[10px] font-bold text-gray-400">
                           <ImageIcon className="w-6 h-6 mb-2 opacity-20" />
                           Aucune photo
                        </div>
                     )}
                  </div>
               </div>

               {/* After Photos */}
               <div className="space-y-4">
                  <div className="flex items-center justify-between">
                     <span className="text-xs font-black text-slate-400 uppercase tracking-widest">{t('details.photo_after')}</span>
                     <label className="cursor-pointer">
                        <input type="file" className="hidden" accept="image/*" onChange={(e) => handleFileUpload(e, 'apres')} />
                        <div className="flex items-center gap-1 text-[10px] font-black text-emerald-600 hover:text-emerald-700 uppercase tracking-widest bg-emerald-50 dark:bg-emerald-900/20 px-3 py-1.5 rounded-xl transition-all">
                           <Plus className="w-3.5 h-3.5" />
                           {t('details.add_photo')}
                        </div>
                     </label>
                  </div>
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                     {photosAfter.map(photo => (
                        <div key={photo.id} className="aspect-square rounded-2xl overflow-hidden relative group border border-gray-100 dark:border-gray-800 shadow-sm">
                           <img src={photo.url} alt="After" className="w-full h-full object-cover transition-transform group-hover:scale-110" />
                           <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                              <button 
                                onClick={() => handleDeletePhoto(photo.id)}
                                className="p-2 bg-red-500 text-white rounded-xl shadow-lg hover:bg-red-600 transition-colors"
                              >
                                {deleting === photo.id ? <Loader2 className="w-4 h-4 animate-spin" /> : <Trash2 className="w-4 h-4" />}
                              </button>
                           </div>
                        </div>
                     ))}
                     {photosAfter.length === 0 && (
                        <div className="aspect-square rounded-2xl bg-slate-50 dark:bg-slate-800/50 border-2 border-dashed border-slate-200 dark:border-slate-700 flex flex-col items-center justify-center text-[10px] font-bold text-gray-400">
                           <ImageIcon className="w-6 h-6 mb-2 opacity-20" />
                           Aucune photo
                        </div>
                     )}
                  </div>
               </div>
             </div>

             {/* Map Placeholder for now */}
             <div className="h-48 bg-slate-50 dark:bg-slate-800/50 rounded-3xl border border-gray-100 dark:border-gray-800 flex items-center justify-center gap-3">
                <div className="w-10 h-10 bg-white dark:bg-slate-700 rounded-full flex items-center justify-center shadow-md">
                   <MapIcon className="w-5 h-5 text-primary-500" />
                </div>
                <span className="text-sm font-bold text-gray-400 uppercase tracking-widest">{t('card.location').split(':')[0]} Map</span>
             </div>
          </div>
